+    #[test]
+    fn test_prepared_memory_query_rejects_cached_read_snapshot_after_commit_epoch_moves() {
+        let _profile_guard = StatementReuseHotPathProfileGuard::new();
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE prep_cached_read_epoch (id INTEGER PRIMARY KEY, val TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO prep_cached_read_epoch VALUES (1, 'alpha');")
+            .unwrap();
+
+        let stmt = conn
+            .prepare("SELECT val FROM prep_cached_read_epoch WHERE id = ?1")
+            .unwrap();
+
+        reset_hot_path_profile();
+        let row = stmt
+            .query_row_with_params(&[SqliteValue::Integer(1)])
+            .unwrap();
+        assert_eq!(row.values()[0], SqliteValue::Text("alpha".into()));
+        let first_profile = hot_path_profile_snapshot();
+        assert_eq!(
+            first_profile.cached_read_snapshot_reuses, 0,
+            "first read should park a fresh snapshot: {first_profile:?}"
+        );
+        assert_eq!(
+            first_profile.cached_read_snapshot_parks, 1,
+            "first read should leave a parked snapshot for reuse: {first_profile:?}"
+        );
+        let first_epoch = conn.cached_read_snapshot_commit_epoch.get();
+        assert!(
+            first_epoch > 0,
+            "parked read snapshot should record the finalized commit epoch"
+        );
+
+        conn.stable_commit_seq.fetch_add(1, AtomicOrdering::AcqRel);
+
+        let row = stmt
+            .query_row_with_params(&[SqliteValue::Integer(1)])
+            .unwrap();
+        assert_eq!(row.values()[0], SqliteValue::Text("alpha".into()));
+        let second_profile = hot_path_profile_snapshot();
+        assert_eq!(
+            second_profile.cached_read_snapshot_reuses, 0,
+            "stale parked read snapshot must not be reused after the commit epoch advances: {second_profile:?}"
+        );
+        assert_eq!(
+            second_profile.cached_read_snapshot_parks, 2,
+            "fresh read after epoch movement should park a replacement snapshot: {second_profile:?}"
+        );
+        assert!(
+            conn.cached_read_snapshot_commit_epoch.get() > first_epoch,
+            "replacement parked snapshot should capture the newer commit epoch"
+        );
+    }
